mapper.select:
SELECT COUNT(*) FROM reservation
WHERE user_no = #{userNo}
  AND status = #{status}
  AND deleted = 0

SELECT r.*, u.name AS userName, u.phone AS userPhone FROM reservation r LEFT JOIN user u ON r.user_no = u.username WHERE r.deleted = 0
AND u.name LIKE CONCAT('%', #{userName}, '%')
AND r.user_no LIKE CONCAT('%', #{userNo}, '%')
AND r.book_name LIKE CONCAT('%', #{bookName}, '%')
AND r.status = #{status}
ORDER BY r.reserve_time DESC LIMIT #{offset}, #{limit}
